SELECT p.id, '${type}' AS silicone_type FROM silicone_${type}_product p INNER JOIN silicone_${type}_compatibility c ON p.id = c.product_id
AND (p.material_name LIKE CONCAT('%', #{keyword}, '%') OR p.material_code LIKE CONCAT('%', #{keyword}, '%') OR p.stock_code LIKE CONCAT('%', #{keyword}, '%') OR p.notes LIKE CONCAT('%', #{keyword}, '%'))
AND c.post_processing_step IN
#{step}
GROUP BY p.id HAVING COUNT(DISTINCT c.post_processing_step) = #{stepCount}
ORDER BY silicone_type, id LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM (
SELECT p.id FROM silicone_${type}_product p INNER JOIN silicone_${type}_compatibility c ON p.id = c.product_id
AND (p.material_name LIKE CONCAT('%', #{keyword}, '%') OR p.material_code LIKE CONCAT('%', #{keyword}, '%') OR p.stock_code LIKE CONCAT('%', #{keyword}, '%') OR p.notes LIKE CONCAT('%', #{keyword}, '%'))
AND c.post_processing_step IN
#{step}
GROUP BY p.id HAVING COUNT(DISTINCT c.post_processing_step) = #{stepCount}
) tmp

SELECT p.*, '${type}' AS silicone_type, c.compatibility_status FROM silicone_${type}_product p LEFT JOIN silicone_${type}_compatibility c ON p.id = c.product_id
AND (p.material_name LIKE CONCAT('%', #{keyword}, '%') OR p.material_code LIKE CONCAT('%', #{keyword}, '%') OR p.stock_code LIKE CONCAT('%', #{keyword}, '%') OR p.notes LIKE CONCAT('%', #{keyword}, '%'))
AND c.post_processing_step = #{stepName}
ORDER BY silicone_type, material_code, id LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM (
SELECT p.id FROM silicone_${type}_product p LEFT JOIN silicone_${type}_compatibility c ON p.id = c.product_id
AND (p.material_name LIKE CONCAT('%', #{keyword}, '%') OR p.material_code LIKE CONCAT('%', #{keyword}, '%') OR p.stock_code LIKE CONCAT('%', #{keyword}, '%') OR p.notes LIKE CONCAT('%', #{keyword}, '%'))
AND c.post_processing_step = #{stepName}
) tmp

SELECT p.*, '${type}' AS silicone_type
FROM silicone_${type}_product p
WHERE p.id = #{id}

SELECT product_id, '${type}' AS silicone_type, post_processing_step, compatibility_status
FROM silicone_${type}_compatibility
WHERE product_id IN

    #{id}

AND post_processing_step IN

    #{step}

SELECT DISTINCT post_processing_step FROM (
SELECT post_processing_step FROM silicone_${type}_compatibility
) steps ORDER BY post_processing_step ASC

SELECT step_category AS "category", post_processing_step AS "step" FROM (
SELECT step_category, post_processing_step FROM silicone_${type}_compatibility WHERE step_category IS NOT NULL
) sc GROUP BY step_category, post_processing_step ORDER BY step_category, post_processing_step
